{"answer":"#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>
#include <string.h>

static const char *p;

static void skip_spaces(void) {
    while (*p && isspace((unsigned char)*p)) p++;
}

double parse_expr(void);

static double parse_factor(void) {
    skip_spaces();
    if (*p == '(') {
        p++;
        double v = parse_expr();
        skip_spaces();
        if (*p == ')') p++;
        return v;
    } else {
        char *end;
        double v = strtod(p, &end);
        p = end;
        return v;
    }
}

static double parse_term(void) {
    double v = parse_factor();
    for (;;) {
        skip_spaces();
        if (*p == '*') {
            p++;
            v *= parse_factor();
        } else if (*p == '/') {
            p++;
            v /= parse_factor();
        } else {
            break;
        }
    }
    return v;
}

double parse_expr(void) {
    double v = parse_term();
    for (;;) {
        skip_spaces();
        if (*p == '+') {
            p++;
            v += parse_term();
        } else if (*p == '-') {
            p++;
            v -= parse_term();
        } else {
            break;
        }
    }
    return v;
}

int main(int argc, char **argv) {
    if (argc < 2) return 0;

    size_t len = 0;
    for (int i = 1; i < argc; i++) len += strlen(argv[i]) + 1;

    char *expr = malloc(len + 1);
    if (!expr) return 1;

    expr[0] = '\0';
    for (int i = 1; i < argc; i++) {
        strcat(expr, argv[i]);
        if (i + 1 < argc) strcat(expr, " ");
    }

    p = expr;
    double res = parse_expr();
    printf("%.10g\n", res);

    free(expr);
    return 0;
}
